import{_ as r,C as n,o as l,c as d,j as t,a,E as o,ag as s}from"./chunks/framework.DLWhSH9p.js";const f=JSON.parse('{"title":"Discover","description":"","frontmatter":{},"headers":[],"relativePath":"guide/discover.md","filePath":"guide/discover.md"}'),c={name:"guide/discover.md"};function h(p,e,g,u,m,v){const i=n("SchemeImage");return l(),d("div",null,[e[0]||(e[0]=t("h1",{id:"discover",tabindex:"-1"},[a("Discover "),t("a",{class:"header-anchor",href:"#discover","aria-label":'Permalink to "Discover"'},"​")],-1)),e[1]||(e[1]=t("p",null,[a("The Discover panel is a YouTube research tool powered by yt-dlp. Search for videos, analyze channels, estimate earnings, and save inspiring content as ideas. Reach it from the top-chrome stage rail — "),t("strong",null,"Discover"),a(" is the leftmost stage.")],-1)),o(i,{name:"discover-search",alt:"Discover — left filter rail, channel strip, video grid"}),e[2]||(e[2]=s('<h2 id="layout" tabindex="-1">Layout <a class="header-anchor" href="#layout" aria-label="Permalink to &quot;Layout&quot;">​</a></h2><ul><li><strong>Left — filter rail.</strong> Search input at the top, then stacked filter sections (Sort by / Duration / Date / Channel size cap / Outlier / Topic tags) and a <strong>Filter loop</strong> status card at the bottom that shows how many videos are currently kept.</li><li><strong>Main — results area.</strong> Channel strip (when applicable) and the progressively-loaded video grid. Infinite scroll pulls more results when you approach the bottom.</li></ul><h2 id="searching" tabindex="-1">Searching <a class="header-anchor" href="#searching" aria-label="Permalink to &quot;Searching&quot;">​</a></h2><p>Type in the <strong>Search</strong> box in the left rail and hit Enter (or click the button beneath it). Results load in batches — scroll down to fetch more. Your channel&#39;s Topic tags show up as pill-buttons in the rail so you can jump straight to relevant queries.</p><div class="tip custom-block"><p class="custom-block-title">No API key needed</p><p>Basic search works without a YouTube API key (uses yt-dlp). Adding a key enables subscriber-cap and outlier filters plus channel comparison. Status is reflected in which filter groups appear in the left rail.</p></div><h2 id="filters" tabindex="-1">Filters <a class="header-anchor" href="#filters" aria-label="Permalink to &quot;Filters&quot;">​</a></h2><p>All filters re-run the search as soon as they change.</p><table tabindex="0"><thead><tr><th>Filter</th><th>Options</th><th>What it does</th></tr></thead><tbody><tr><td><strong>Sort by</strong></td><td>Relevance / Most viewed / Newest</td><td>Result ordering</td></tr><tr><td><strong>Duration</strong></td><td>Any / &lt; 4 min (Shorts) / 4–20 min / 20+ min</td><td>Video length</td></tr><tr><td><strong>Date</strong></td><td>Any time / Past week / Past month / Past year</td><td>Recency</td></tr><tr><td><strong>Channel size cap</strong></td><td>Any / &lt; 1M / &lt; 100K / &lt; 10K / &lt; 1K</td><td>Subscriber cap — requires API key</td></tr><tr><td><strong>Outlier</strong></td><td>Any / ≥ 5× / ≥ 10× / ≥ 50×</td><td>Videos with views well above the channel&#39;s average — requires API key</td></tr><tr><td><strong>Topic tags</strong></td><td>Pill-buttons from your channel config</td><td>One-click topical searches</td></tr></tbody></table><h2 id="filter-loop" tabindex="-1">Filter loop <a class="header-anchor" href="#filter-loop" aria-label="Permalink to &quot;Filter loop&quot;">​</a></h2><p>Because tight filters (e.g. 10× outliers + &lt;10K subs) can eliminate most of any given batch, the backend searches progressively wider — up to ~6000 raw results — to surface matches. The <strong>Filter loop</strong> card at the bottom of the left rail shows live status (<code>142 kept</code>, <code>exhausted</code>, <code>searching…</code>) so you can tell whether to wait or loosen a filter.</p><h2 id="channel-deep-dive" tabindex="-1">Channel deep dive <a class="header-anchor" href="#channel-deep-dive" aria-label="Permalink to &quot;Channel deep dive&quot;">​</a></h2>',11)),o(i,{name:"channel-dive",alt:"Channel Deep Dive"}),e[3]||(e[3]=s('<p>Click a <strong>channel name</strong> (accent link) on any video card to open the deep dive. The main column switches to channel-focused view.</p><p><strong>Analytics</strong></p><ul><li><strong>Subscribers</strong>, <strong>Total Views</strong>, <strong>Video Count</strong></li><li><strong>Avg Views</strong>, <strong>Upload Frequency</strong>, <strong>Engagement Rate</strong></li><li><strong>Subs/Day</strong>, <strong>Shorts Ratio</strong>, <strong>Videos in last 30 days</strong></li><li><strong>Monetization</strong> badge (≥1K subs + ≥4K watch hours in 12 months)</li></ul><p><strong>Estimated earnings</strong></p><p>Based on your channel&#39;s RPM setting (configurable in <a href="/guide/settings.html">Settings</a>):</p><ul><li><strong>Monthly revenue</strong> — estimated monthly views × RPM</li><li><strong>Per video</strong> — average views × RPM</li><li><strong>30-day views</strong> — projected monthly view count</li></ul><p><strong>Channel comparison</strong></p><p>Click <strong>+ Add this channel</strong> to add to the comparison table. Compare up to 3 channels side-by-side: subs, total views, avg views, and estimated earnings per video.</p><p><strong>Recent videos</strong></p><p>Scrollable list of the latest uploads. Click any to view full metadata.</p><h2 id="video-detail" tabindex="-1">Video detail <a class="header-anchor" href="#video-detail" aria-label="Permalink to &quot;Video detail&quot;">​</a></h2><p>Click any video card to expand in-place and see full metadata:</p><ul><li>Views, likes, comments, duration, upload date</li><li>Full description</li><li>Tags and categories</li><li>Chapters (if available)</li><li><strong>Transcript</strong> — fetches and displays captions</li><li><strong>Inspire</strong> — creates an idea with all enrichment data</li></ul><h2 id="inspire" tabindex="-1">Inspire <a class="header-anchor" href="#inspire" aria-label="Permalink to &quot;Inspire&quot;">​</a></h2><p>Every video card has an <strong>Inspire</strong> button. It creates an idea with:</p><ul><li>Video title as the idea title</li><li>Channel name in the hook</li><li>Enrichment: views, duration, description, transcript (if fetched)</li><li>Source: <code>discover</code>, with the original URL stored for attribution</li></ul><p>The idea appears immediately in the Ideas panel, tagged <code>⊕ Discover</code> with the view count visible in the list&#39;s source column.</p>',17))])}const y=r(c,[["render",h]]);export{f as __pageData,y as default};
